import { defineConfig } from 'vite'
import react from '@vitejs/plugin-react'
import tailwindcss from '@tailwindcss/vite'
import fs from 'fs'
import path from 'path'

const CONTEXT_ROOT = path.resolve(process.env.USERPROFILE || '', '.claude/context')
const OUTPUT_ROOT = path.resolve(process.env.USERPROFILE || '', '.claude/output')

const today = new Date().toISOString().split('T')[0]

// daily: true = 今日更新されたかで判定, false = 内容があれば完了
// タスクは PDCA思想①〜④に対応: ①着地見込 ②示唆 ③チャンス・課題 ④活動修正・戦略見直し
const FILE_MAP = [
  // Researcher: ①②の主担当
  { agentId: 'researcher', label: '①当月売上実績収集', file: 'market/market-trends.md', daily: true },
  { agentId: 'researcher', label: '②市場・競合分析', file: 'market/competitors.md', daily: true },
  { agentId: 'researcher', label: '②口コミ・LP分析', file: 'market/reviews-wom.md', daily: true },
  { agentId: 'researcher', label: 'レビュー：市場データ', file: 'reviews/review-market-sales.md', daily: true },
  // CMO: 全4柱の司令塔
  { agentId: 'cmo', label: '①着地見込・GAP算出', file: 'strategy/monthly-kpi-tracking.md', daily: true },
  { agentId: 'cmo', label: '②GAP要因分析', file: `strategy/daily-review-${today}.md`, daily: true },
  { agentId: 'cmo', label: '③チャンス・課題特定', file: 'strategy/kpi-targets.md', daily: false },
  { agentId: 'cmo', label: '④活動修正・戦略見直し', file: 'strategy/annual-plan.md', daily: false },
  { agentId: 'cmo', label: 'レビュー：統括', file: 'reviews/review-strategy.md', daily: true },
  // Communication Planner: ③④の主担当
  { agentId: 'planner', label: '③コミュ施策評価', file: 'communication/integrated-plan.md', daily: false },
  { agentId: 'planner', label: '④広告・SNS修正', file: 'communication/media-sns.md', daily: false },
  { agentId: 'planner', label: '③CRM施策評価', file: 'communication/crm-plan.md', daily: false },
  { agentId: 'planner', label: 'レビュー：コミュ', file: 'reviews/review-communication.md', daily: true },
  // CSO: ①③④
  { agentId: 'cso', label: '①パイプライン・受注実績', file: 'sales/pipeline.md', daily: true },
  { agentId: 'cso', label: '③営業チャンス・課題', file: 'sales/customer-insights.md', daily: true },
  { agentId: 'cso', label: '④営業戦術修正', file: 'sales/sales-tactics.md', daily: true },
  { agentId: 'cso', label: 'レビュー：営業', file: 'reviews/review-sales.md', daily: true },
  // CTO: ②③④
  { agentId: 'cto', label: '②分析基盤・データ精度', file: 'tech/prompts.md', daily: true },
  { agentId: 'cto', label: '③技術チャンス・課題', file: 'tech/tech-improvements.md', daily: true },
  { agentId: 'cto', label: '④プロンプト・自動化改善', file: 'tech/claude-code-tips.md', daily: true },
  { agentId: 'cto', label: 'レビュー：技術', file: 'reviews/review-tech.md', daily: true },
]

function isTemplate(content: string): boolean {
  if (!content || content.trim().length < 200) return true
  const markers = ['<!-- ここに']
  return markers.some(m => content.includes(m))
}

function isUpdatedToday(filePath: string): boolean {
  try {
    const stat = fs.statSync(filePath)
    const mtime = new Date(stat.mtime)
    const todayDate = new Date()
    return (
      mtime.getFullYear() === todayDate.getFullYear() &&
      mtime.getMonth() === todayDate.getMonth() &&
      mtime.getDate() === todayDate.getDate()
    )
  } catch {
    return false
  }
}

function getProgress() {
  const agentMap: Record<string, { agentId: string; tasks: { label: string; file: string; status: string }[] }> = {}

  for (const entry of FILE_MAP) {
    if (!agentMap[entry.agentId]) {
      agentMap[entry.agentId] = { agentId: entry.agentId, tasks: [] }
    }
    const filePath = path.join(CONTEXT_ROOT, entry.file)
    let status = 'pending'
    try {
      const content = fs.readFileSync(filePath, 'utf-8')
      if (entry.daily) {
        // 日次タスク: 今日更新されたかで判定
        const updatedToday = isUpdatedToday(filePath)
        if (!updatedToday) {
          status = 'pending'
        } else if (isTemplate(content)) {
          status = 'in_progress'
        } else {
          status = 'done'
        }
      } else {
        // 基盤ファイル: 内容があれば完了
        status = isTemplate(content) ? 'in_progress' : 'done'
      }
    } catch {
      status = 'pending'
    }
    agentMap[entry.agentId].tasks.push({ label: entry.label, file: entry.file, status })
  }
  return Object.values(agentMap)
}

export default defineConfig({
  plugins: [
    react(),
    tailwindcss(),
    {
      name: 'progress-api',
      configureServer(server) {
        server.middlewares.use('/api/progress', (_req, res) => {
          res.setHeader('Content-Type', 'application/json')
          res.setHeader('Cache-Control', 'no-cache, no-store, must-revalidate')
          res.setHeader('Pragma', 'no-cache')
          res.end(JSON.stringify(getProgress()))
        })

        server.middlewares.use('/api/sns-monitoring', (_req, res) => {
          res.setHeader('Content-Type', 'application/json')
          res.setHeader('Cache-Control', 'no-cache, no-store, must-revalidate')
          const filePath = path.join(CONTEXT_ROOT, 'memos/sns-monitoring-plan.md')
          try {
            const content = fs.readFileSync(filePath, 'utf-8')
            const stat = fs.statSync(filePath)
            res.end(JSON.stringify({ content, found: true, lastModified: stat.mtime.toISOString() }))
          } catch {
            res.end(JSON.stringify({ content: null, found: false, lastModified: null }))
          }
        })

        server.middlewares.use('/api/researcher-sources', (_req, res) => {
          res.setHeader('Content-Type', 'application/json')
          res.setHeader('Cache-Control', 'no-cache, no-store, must-revalidate')
          const sourcesPath = path.join(CONTEXT_ROOT, 'market/researcher-sources.md')
          try {
            const content = fs.readFileSync(sourcesPath, 'utf-8')
            res.end(JSON.stringify({ content, found: true }))
          } catch {
            res.end(JSON.stringify({ content: null, found: false }))
          }
        })

        server.middlewares.use('/api/kpi-tracking', (_req, res) => {
          res.setHeader('Content-Type', 'application/json')
          res.setHeader('Cache-Control', 'no-cache, no-store, must-revalidate')
          const filePath = path.join(CONTEXT_ROOT, 'strategy/monthly-kpi-tracking.md')
          try {
            const content = fs.readFileSync(filePath, 'utf-8')
            res.end(JSON.stringify({ content, found: true }))
          } catch {
            res.end(JSON.stringify({ content: null, found: false }))
          }
        })

        server.middlewares.use('/api/daily-output', (_req, res) => {
          res.setHeader('Content-Type', 'application/json')
          res.setHeader('Cache-Control', 'no-cache, no-store, must-revalidate')
          res.setHeader('Pragma', 'no-cache')
          const todayStr = new Date().toISOString().split('T')[0]
          const filePath = path.join(OUTPUT_ROOT, `daily-review-${todayStr}.md`)
          try {
            const content = fs.readFileSync(filePath, 'utf-8')
            res.end(JSON.stringify({ date: todayStr, content, found: true }))
          } catch {
            // Fall back to most recent daily review
            try {
              const files = fs.readdirSync(OUTPUT_ROOT)
                .filter(f => f.startsWith('daily-review-') && f.endsWith('.md') && !f.includes('v'))
                .sort()
                .reverse()
              if (files.length > 0) {
                const latest = files[0]
                const latestContent = fs.readFileSync(path.join(OUTPUT_ROOT, latest), 'utf-8')
                const latestDate = latest.replace('daily-review-', '').replace('.md', '')
                res.end(JSON.stringify({ date: latestDate, content: latestContent, found: false }))
              } else {
                res.end(JSON.stringify({ date: todayStr, content: null, found: false }))
              }
            } catch {
              res.end(JSON.stringify({ date: todayStr, content: null, found: false }))
            }
          }
        })
      },
    },
  ],
})

